// Generate random RSI with some consistency based on symbol
const generateRSI = (symbol: string): number => {
  const hash = symbol.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
  return 25 + (hash % 50) + Math.floor(Math.random() * 5);
};

// Generate holdings with some variance
const generateHoldings = (marketCap: number): { promoter: number; fii: number; dii: number } => {
  const isLargeCap = marketCap > 100000;
  const promoter = isLargeCap ? 40 + Math.random() * 25 : 50 + Math.random() * 20;
  const fii = isLargeCap ? 15 + Math.random() * 20 : 5 + Math.random() * 15;
  const dii = isLargeCap ? 10 + Math.random() * 15 : 5 + Math.random() * 10;
  return { promoter, fii, dii };
};

// Generate 52-week range based on market cap and sector
const generate52WeekRange = (marketCap: number, sector: string): { high: number; low: number } => {
  const basePrice = Math.max(50, Math.min(5000, marketCap / 100));
  const volatility = ["Metals", "Energy", "Oil & Gas", "Realty"].includes(sector) ? 0.4 :
                     ["IT", "Pharma"].includes(sector) ? 0.35 :
                     ["Banking", "NBFC", "Private Bank", "PSU Bank"].includes(sector) ? 0.3 : 0.28;
  
  return {
    high: Math.round(basePrice * (1 + volatility)),
    low: Math.round(basePrice * (1 - volatility * 0.8))
  };
};

// Build complete stock database
export const allStocks: StockInfo[] = stocksRaw.map(stock => {
  const defaults = sectorDefaults[stock.sector] || sectorDefaults["Diversified"];
  const range = generate52WeekRange(stock.marketCap, stock.sector);
  const holdings = generateHoldings(stock.marketCap);
  
  const variance = () => 0.75 + Math.random() * 0.5;
  
  return {
    symbol: stock.symbol,
    name: stock.name,
    sector: stock.sector,
    industry: stock.industry,
    marketCap: stock.marketCap,
    indices: stock.indices,
    peRatio: Math.round((defaults.peRatio || 20) * variance() * 10) / 10,
    pbRatio: Math.round((defaults.pbRatio || 3) * variance() * 10) / 10,
    eps: Math.round(stock.marketCap / 800 * variance() * 10) / 10,
    dividendYield: Math.round((defaults.dividendYield || 1) * variance() * 10) / 10,
    debtToEquity: Math.round((defaults.debtToEquity || 0.5) * variance() * 100) / 100,
    roe: Math.round((defaults.roe || 15) * variance() * 10) / 10,
    roce: Math.round((defaults.roce || 15) * variance() * 10) / 10,
    rsi: generateRSI(stock.symbol),
    high52Week: range.high,
    low52Week: range.low,
    promoterHolding: Math.round(holdings.promoter * 10) / 10,
    fiiHolding: Math.round(holdings.fii * 10) / 10,
    diiHolding: Math.round(holdings.dii * 10) / 10,
  };
});

// Get all unique sectors
export const sectors = ["All", ...Array.from(new Set(allStocks.map(s => s.sector))).sort()];

// Get all unique industries
export const industries = ["All", ...Array.from(new Set(allStocks.map(s => s.industry))).sort()];

// Get symbols for API calls
export const stockSymbols = allStocks.map(s => s.symbol);

